DetectionRule.DetectionLogic:
let SuspiciousCommands = dynamic([ "vssadmin delete shadows", "wmic shadowcopy delete", "bcdedit /set {default} recoveryenabled no", "bcdedit /set {default} bootstatuspolicy ignoreallfailures", "wbadmin delete catalog", "wbadmin delete systemstatebackup" ]);
let SuspiciousPowerShell = @" (Get-WmiObject Win32_ShadowCopy).Delete() | Remove-WmiObject -Query "SELECT * FROM Win32_ShadowCopy" | Remove-WmiObject | Set-ItemProperty -Path "HKLM:\SYSTEM\CurrentControlSet\Services\VSS" "@;
DeviceProcessEvents | where Timestamp > ago(1h) | where // Command line shadow copy deletion (CommandLine has_any (SuspiciousCommands) and not CommandLine contains "@") or // PowerShell shadow copy manipulation (ProcessCommandLine has_any (split(SuspiciousPowerShell, '|')) and ProcessCommandLine !contains "Get-Help") or // WMI shadow copy deletion (ProcessCommandLine contains "Win32_ShadowCopy" and ProcessCommandLine contains "Delete") or // Registry modification disabling shadow copies (ActionType == "RegistryValueSet" and RegistryKey endswith "\VSS" and RegistryValueName in~ ("ShadowCopyStorage", "MinDiffAreaFileSize")) | extend CommandLower = tolower(CommandLine) | where CommandLower !contains "test" and CommandLower !contains "#" and CommandLower !contains "*echo*" | extend ThreatScore = case( CommandLine has "bcdedit" and CommandLine has "recoveryenabled no", 95, CommandLine has "vssadmin delete", 90, CommandLine has "wmic shadowcopy", 88, true, 85 ) | project-reorder Timestamp, DeviceId, FileName, CommandLine, ThreatScore

let SuspiciousParents = dynamic([ "winword.exe", "excel.exe", "powerpnt.exe", "outlook.exe", "acrord32.exe", "rdpclip.exe", "mshta.exe", "regsvr32.exe" ]);
let SuspiciousChildren = dynamic([ "cmd.exe", "powershell.exe", "wscript.exe", "cscript.exe", "msiexec.exe", "rundll32.exe", "certutil.exe", "bitsadmin.exe", "psexec.exe", "wmic.exe", "schtasks.exe", "at.exe" ]);
let RansomwareIndicators = dynamic([ "-enc", "-EncodedCommand", "-ExecutionPolicy", "-nop", "IEX", "Invoke-Expression", "DownloadFile", "DownloadString", "Net.WebClient", "Start-BitsTransfer", "Invoke-WebRequest" ]);
DeviceProcessEvents | where Timestamp > ago(2h) | where InitiatingProcessFileName in~ (SuspiciousParents) or InitiatingProcessFileName in~ (SuspiciousChildren) | where FileName in~ (SuspiciousChildren) or (FileName endswith ".ps1" and ProcessCommandLine has_any (RansomwareIndicators)) or ProcessCommandLine has_any (RansomwareIndicators) | extend ParentChildCombo = strcat(InitiatingProcessFileName, " -> ", FileName) | extend RiskScore = case( InitiatingProcessFileName in~ (SuspiciousParents) and FileName == "powershell.exe", 95, InitiatingProcessFileName in~ (SuspiciousParents) and FileName == "cmd.exe", 90, InitiatingProcessFileName endswith "rundll32.exe" and ProcessCommandLine contains "-s", 98, InitiatingProcessFileName == "mshta.exe", 93, true, 85 ) | where RiskScore >= 85 | summarize EventCount = count(), RiskScore = max(RiskScore), Commands = makeset(ProcessCommandLine) by DeviceId, InitiatingProcessFileName, InitiatingProcessCommandLine, FileName, ProcessCommandLine, ParentChildCombo | where EventCount >= 2 or RiskScore >= 90 | project-reorder Timestamp, DeviceId, ParentChildCombo, RiskScore, EventCount
